#include <stdio.h>


int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        char str[1002];
        scanf("%s", str);
        int sum = 0; 
        for (int i = 0; str[i] != '\0'; i++) {
            char ch = str[i];
            if (ch >= '0' && ch <= '9') {
                sum += str[i] - '0'; // Convert character to integer and add to sum
            }
        }
        printf("%d\n", sum);
    }

    return 0;
}
